<template>
  <div class="date_range">
    <label class="form-check form-check-inline text-center">
      <span class="eraseall text-white">{{ $t('DateRange') }}</span>
      <i v-if="showNavigation" class="fa fa-caret-left text-info fa-2x px-1" style="cursor:pointer;" 
         :title="$t('Previous')" @click="$emit('previous-date')"></i>
      <i v-if="showNavigation" class="fa fa-caret-right text-info fa-2x" style="cursor:pointer;" 
         :title="$t('Next')" @click="$emit('next-date')"></i>
    </label>
    
    <a href="javascript:;" style="cursor:pointer; font-size: 12px;" 
       class="btn btn-info formbtn inline-block showDatePanel tbdaterange" @click="toggleDatePanel">
      <span class="mr-2">{{ displayText }}</span>
      <i style="cursor:pointer;" class="fa fa-bars"></i>
    </a>

    <div class="DatePopUp divtimer_design p-1" v-show="showDatePanel" 
         style="position: absolute; z-index: 1000; background: white; border: 1px solid #ccc; margin-top: 5px; right: 0; width: 350px;">
      <table class="table-responsive AssetDatePopUp d-block">
        <tbody class="daterangebody">
          <tr class="daterangetr">
            <td class="sep daterangetd">
              <ul class="date_select list-unstyled">
                <li><a @click="selectDateRange('today')" :title="$t('Today')">{{ $t('Today') }}</a></li>
                <li><a @click="selectDateRange('yesterday')" :title="$t('Yesterday')">{{ $t('Yesterday') }}</a></li>
                <li><a @click="selectDateRange('thisweek')" :title="$t('thisWeek')">{{ $t('thisWeek') }}</a></li>
                <li><a @click="selectDateRange('all')" :title="$t('AllTime')">{{ $t('AllTime') }}</a></li>
              </ul>
            </td>
            <td valign="top" class="daterangetd">
              <ul class="date_select list-unstyled">
                <li><a @click="selectDateRange('lastweek')" :title="$t('LastWeek')">{{ $t('LastWeek') }}</a></li>
                <li><a @click="selectDateRange('thismonth')" :title="$t('thisMonth')">{{ $t('thisMonth') }}</a></li>
                <li><a @click="selectDateRange('lastmonth')" :title="$t('LastMonth')">{{ $t('LastMonth') }}</a></li>
              </ul>
            </td>
          </tr>
          <tr class="float-left p-0 m-0 mt-1 col-12 daterangetr">
            <td class="col-5 m-1 daterangetd table_datepickerfix">
              <span>{{ $t('From') }}...</span><br />
              <input name="startDate" type="date" class="FromDate form-control p-1" 
                     v-model="customFromDate" @change="onCustomDateChange" />
            </td>
            <td class="col-5 m-1 daterangetd table_datepickerfix">
              <span class="ml-2">...{{ $t('To') }}</span><br />
              <input name="endDate" type="date" class="ToDate form-control p-1" 
                     v-model="customToDate" @change="onCustomDateChange" />
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</template>
<script>
import moment from 'moment';

export default {
  name: 'DateRangeSelector',
  props: {
    dateSpan: {
      type: String,
      default: 'month'
    },
    fromDate: {
      type: Date,
      required: true
    },
    toDate: {
      type: Date,
      required: true
    },
    displayText: {
      type: String,
      default: ''
    }
  },
  data() {
    return {
      showDatePanel: false,
      customFromDate: '',
      customToDate: '',
      showNavigation: true
    };
  },
  watch: {
    fromDate: {
      immediate: true,
      handler(newVal) {
        this.customFromDate = this.formatDateForInput(newVal);
      }
    },
    toDate: {
      immediate: true,
      handler(newVal) {
        this.customToDate = this.formatDateForInput(newVal);
      }
    },
    dateSpan(newVal) {
      this.showNavigation = newVal !== 'all';
    }
  },
  mounted() {
    this.showNavigation = this.dateSpan !== 'all';
    document.addEventListener('click', this.handleClickOutside);
  },
  beforeDestroy() {
    document.removeEventListener('click', this.handleClickOutside);
  },
  methods: {
    toggleDatePanel() {
      this.showDatePanel = !this.showDatePanel;
    },

    selectDateRange(rangeType) {
      console.log('Date range selected:', rangeType);
      this.showDatePanel = false;
      this.$emit('date-range-changed', {
        dateSpan: rangeType,
        startDate: this.fromDate, 
        endDate: this.toDate,     
        displayText: this.$t(this.getDisplayTextForRange(rangeType))
      });
    },

    getDisplayTextForRange(rangeType) {
      const texts = {
        today: 'Today',
        yesterday: 'Yesterday',
        thisweek: 'thisWeek',      
        lastweek: 'LastWeek',
        thismonth: 'thisMonth',     
        lastmonth: 'LastMonth',
        all: 'AllTime'
  };
  return texts[rangeType] || 'thisMonth'; 
},

    onCustomDateChange() {
      if (this.customFromDate && this.customToDate) {
        const startDate = new Date(this.customFromDate);
        const endDate = new Date(this.customToDate);
        
        // Format dates for display using moment.js for consistency
        const displayStart = moment(startDate).format('MM/DD/YYYY');
        const displayEnd = moment(endDate).format('MM/DD/YYYY');
        
        this.$emit('date-range-changed', {
          dateSpan: 'custom',
          startDate: startDate,
          endDate: endDate,
          displayText: `${displayStart} - ${displayEnd}`
        });
        
        this.showDatePanel = false;
      }
    },

    formatDateForInput(date) {
      if (!date) return '';
      return moment(date).format('YYYY-MM-DD');
    },

    handleClickOutside(event) {
      if (!this.$el.contains(event.target)) {
        this.showDatePanel = false;
      }
    }
  }
};
</script>

<style scoped>
.divtimer_design table.AssetDatePopUp {
  margin-bottom: 0;
}

.divtimer_design table.AssetDatePopUp td.daterangetd {
  padding: 0 !important;
  text-align: left;
  vertical-align: top;
  font-size: 12px;
}

.divtimer_design table.AssetDatePopUp td.sep {
  border-right: 1px solid #D2D2D2;
}

.date_select {
  list-style: none;
  padding: 0;
  margin: 0;
}

.date_select li {
  padding: 5px 10px;
  cursor: pointer;
}

.date_select li:hover {
  background-color: #f5f5f5;
}

.date_select a {
  color: #333;
  text-decoration: none;
  display: block;
}

.date_range {
  margin: 0px -3px;
  width: calc(100% + 6px);
}

.btn-info {
  background-color: #138496;
  border-color: #138496;
}
</style>

 